body.script:
        const gameBoard = document.getElementById('game-board');
        const timerDisplay = document.getElementById('time');
        const completionMessage = document.getElementById('completion-message');

        // --- IMPORTANT: Provide 14 unique image paths here ---
        const imageSources = [
			'https://img.r7.com/images/football/teams/134.png', // Athletico-PR
			'https://img.r7.com/images/football/teams/1062.png', // Atletico-MG
			'https://img.r7.com/images/football/teams/118.png', // Bahia
			'https://img.r7.com/images/football/teams/120.png', // Botafogo
			'https://img.r7.com/images/football/teams/132.png', // Chapecoense
			'https://img.r7.com/images/football/teams/131.png', // Corinthians
			'https://img.r7.com/images/football/teams/147.png', // Coritiba
			'https://img.r7.com/images/football/teams/135.png', // Cruzeiro
			'https://img.r7.com/images/football/teams/127.png', // Flamengo
			'https://img.r7.com/images/football/teams/124.png', // Fluminense
			'https://img.r7.com/images/football/teams/130.png', // Gremio
			'https://img.r7.com/images/football/teams/119.png', // Internacional
			'https://img.r7.com/images/football/teams/7848.png', // Mirassol
			'https://img.r7.com/images/football/teams/121.png', // Palmeiras
			'https://img.r7.com/images/football/teams/794.png', // RB Bragantino
			'https://img.r7.com/images/football/teams/1198.png', // Remo
			'https://img.r7.com/images/football/teams/128.png', // Santos
			'https://img.r7.com/images/football/teams/126.png', // Sao Paulo
			'https://img.r7.com/images/football/teams/133.png', // Vasco
			'https://img.r7.com/images/football/teams/136.png' // Vitoria
		        ];
        const coverImage = 'https://esportes.r7.com/resizer/v2/URKFY5FRS5EVNML5LSUADIWK3U.jpg?auth=4b1a88ff866b1dc515f4cd0343225de08e2a3b39399d0517904fb6542b4d179c';

        let cards = [];
        let flippedCards = [];
        let matchedPairs = 0;
        let totalPairs;


        let timerInterval;
        let seconds = 0;
        let gameStarted = false;
        let boardLocked = false;

        function startTimer() {
            if (gameStarted && timerInterval) return;
            gameStarted = true;
            seconds = 0;
            timerDisplay.textContent = seconds;
            timerInterval = setInterval(() => {
                seconds++;
                timerDisplay.textContent = seconds;
            }, 1000);
        }

        function stopTimer() {
            clearInterval(timerInterval);
            timerInterval = null;
        }

        function initializeGame() {
            if (imageSources.length * 2 !== 40) {
                console.error("Error: Please provide exactly 20 unique image sources for a 40-tile game.");
                gameBoard.innerHTML = "
Game Configuration Error: Not enough images provided for a 4x10 grid. Please check the console.";
                return;
            }
            totalPairs = imageSources.length;

            stopTimer();
            gameStarted = false;
            seconds = 0;
            matchedPairs = 0;
            flippedCards = [];
            cards = [];
            gameBoard.innerHTML = '';
            completionMessage.style.display = 'none';
            timerDisplay.textContent = seconds;
            boardLocked = false;

            let gameImages = [...imageSources, ...imageSources];
            shuffleArray(gameImages);

            gameImages.forEach(imageSrc => {
                const card = createCard(imageSrc);
                cards.push(card);
                gameBoard.appendChild(card.element);
            });

            startTimer();
        }

        function shuffleArray(array) {
            for (let i = array.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [array[i], array[j]] = [array[j], array[i]];
            }
        }

        function createCard(imageSrc) {
            const cardElement = document.createElement('div');
            cardElement.classList.add('card');
            cardElement.dataset.image = imageSrc;

            const cardFront = document.createElement('div');
            cardFront.classList.add('card-face', 'card-front');
            const frontImg = document.createElement('img');
            frontImg.src = imageSrc;
            frontImg.alt = "Card Image";
            cardFront.appendChild(frontImg);

            const cardBack = document.createElement('div');
            cardBack.classList.add('card-face', 'card-back');
            const backImg = document.createElement('img');
            backImg.src = coverImage;
            backImg.alt = "Card Cover";
            cardBack.appendChild(backImg);

            cardElement.appendChild(cardFront);
            cardElement.appendChild(cardBack);

            cardElement.addEventListener('click', () => handleCardClick(cardElement));

            return { element: cardElement, image: imageSrc, isFlipped: false, isMatched: false };
        }

        function handleCardClick(clickedCardElement) {
            if (boardLocked) return;

            const clickedCardObject = cards.find(cardObj => cardObj.element === clickedCardElement);

            if (!clickedCardObject || clickedCardObject.isFlipped || clickedCardObject.isMatched) {
                return;
            }

            flipCard(clickedCardObject);
            flippedCards.push(clickedCardObject);

            if (flippedCards.length === 2) {
                boardLocked = true;
                checkForMatch();
            }
        }

        function flipCard(cardObject) {
            cardObject.element.classList.add('flipped');
            cardObject.isFlipped = true;
        }

        function checkForMatch() {
            const [card1, card2] = flippedCards;

            if (card1.image === card2.image) {
                card1.isMatched = true;
                card2.isMatched = true;
                card1.element.classList.add('matched'); // This triggers .card.matched .card-back { opacity: 0; }
                card2.element.classList.add('matched');
                // .flipped class remains on matched cards
                matchedPairs++;
                flippedCards = [];
                boardLocked = false;

                if (matchedPairs === totalPairs) {
                    endGame();
                }
            } else {
                setTimeout(() => {
                    unflipCard(card1);
                    unflipCard(card2);
                    flippedCards = [];
                    boardLocked = false;
                }, 1000);
            }
        }

        function unflipCard(cardObject) {
            if (cardObject && !cardObject.isMatched) {
                cardObject.element.classList.remove('flipped');
                cardObject.isFlipped = false;
            }
        }

        function endGame() {
            stopTimer();
            completionMessage.style.display = 'block';
        }

        document.addEventListener('DOMContentLoaded', initializeGame);
